import { useEffect, useRef, useState } from "react";
import { sim } from "@/lib/game/sim";
import { useGame } from "@/lib/game/store";

// Virtual joystick for movement
function VirtualJoystick({ onMove }: { onMove: (x: number, y: number) => void }) {
  const ref = useRef<HTMLDivElement>(null);
  const [active, setActive] = useState(false);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const startRef = useRef({ x: 0, y: 0 });

  const handleStart = (e: React.TouchEvent | React.MouseEvent) => {
    e.preventDefault();
    const touch = "touches" in e ? e.touches[0] : e;
    const rect = ref.current?.getBoundingClientRect();
    if (!rect) return;

    startRef.current = { x: touch.clientX, y: touch.clientY };
    setActive(true);
  };

  const handleMove = (e: React.TouchEvent | React.MouseEvent) => {
    if (!active) return;
    e.preventDefault();
    const touch = "touches" in e ? e.touches[0] : e;
    const dx = touch.clientX - startRef.current.x;
    const dy = touch.clientY - startRef.current.y;
    const dist = Math.min(Math.hypot(dx, dy), 50); // Max radius 50px
    const angle = Math.atan2(dy, dx);

    const normalizedX = (Math.cos(angle) * dist) / 50;
    const normalizedY = (Math.sin(angle) * dist) / 50;

    setPosition({ x: normalizedX, y: normalizedY });
    onMove(normalizedX, normalizedY);
  };

  const handleEnd = () => {
    setActive(false);
    setPosition({ x: 0, y: 0 });
    onMove(0, 0);
  };

  return (
    <div
      ref={ref}
      className="pointer-events-auto absolute bottom-24 left-4 z-50 h-32 w-32 touch-none"
      onMouseDown={handleStart}
      onMouseMove={handleMove}
      onMouseUp={handleEnd}
      onMouseLeave={handleEnd}
      onTouchStart={handleStart}
      onTouchMove={handleMove}
      onTouchEnd={handleEnd}
    >
      <div className="relative h-full w-full">
        {/* Base */}
        <div className="absolute inset-0 rounded-full border-2 border-white/20 bg-black/30 backdrop-blur-sm" />
        {/* Stick */}
        <div
          className="absolute h-12 w-12 rounded-full bg-cyan-400/60 shadow-[0_0_15px_rgba(61,232,255,0.6)] transition-transform"
          style={{
            left: `calc(50% - 24px + ${position.x * 40}px)`,
            top: `calc(50% - 24px + ${position.y * 40}px)`,
          }}
        />
      </div>
    </div>
  );
}

// Touch aiming and firing
function TouchAim() {
  const ref = useRef<HTMLDivElement>(null);
  const [aiming, setAiming] = useState(false);

  const handleTouch = (e: React.TouchEvent) => {
    e.preventDefault();
    const touch = e.touches[0];
    const rect = ref.current?.getBoundingClientRect();
    if (!rect) return;

    const x = touch.clientX - rect.left;
    const y = touch.clientY - rect.top;

    // Convert to world coordinates relative to player
    const worldX = (x - rect.width / 2) * 0.3;
    const worldZ = -(y - rect.height / 2) * 0.3;

    sim.aimPx = sim.px + worldX;
    sim.aimPz = sim.pz + worldZ;
    setAiming(true);
  };

  const handleTap = (e: React.TouchEvent) => {
    e.preventDefault();
    sim.firing = true;
    setTimeout(() => { sim.firing = false; }, 50);
  };

  return (
    <div
      ref={ref}
      className="pointer-events-auto absolute bottom-24 right-4 z-50 h-40 w-40 touch-none"
      onTouchStart={handleTouch}
      onTouchMove={handleTouch}
      onTouchEnd={() => { setAiming(false); sim.firing = false; }}
      onTouchCancel={() => { setAiming(false); sim.firing = false; }}
      onClick={handleTap}
    >
      <div className="relative h-full w-full">
        {/* Reticle */}
        <div
          className={`absolute left-1/2 top-1/2 h-12 w-12 -translate-x-1/2 -translate-y-1/2 rounded-full border-2 transition-all
            ${aiming ? "border-cyan-300 bg-cyan-400/20 shadow-[0_0_20px_rgba(61,232,255,0.5)]" : "border-white/20 bg-black/30"}
          `}
        >
          <div className="absolute left-1/2 top-1/2 h-1 w-1 -translate-x-1/2 -translate-y-1/2 rounded-full bg-cyan-300" />
        </div>
        <div className="absolute left-1/2 top-1/2 h-24 w-24 -translate-x-1/2 -translate-y-1/2 rounded-full border border-white/10" />
        <div className="absolute left-1/2 top-1/2 h-40 w-40 -translate-x-1/2 -translate-y-1/2 rounded-full border border-white/5" />
      </div>
    </div>
  );
}

// Fire button for mobile
function FireButton() {
  const [pressed, setPressed] = useState(false);

  return (
    <button
      className="pointer-events-auto absolute bottom-4 right-4 z-50 h-20 w-20 rounded-full bg-red-500/80 shadow-[0_0_20px_rgba(255,60,80,0.6)] backdrop-blur-sm active:scale-95 active:bg-red-400/90"
      onTouchStart={(e) => { e.preventDefault(); setPressed(true); sim.firing = true; }}
      onTouchEnd={(e) => { e.preventDefault(); setPressed(false); sim.firing = false; }}
      onMouseDown={() => { setPressed(true); sim.firing = true; }}
      onMouseUp={() => { setPressed(false); sim.firing = false; }}
      onMouseLeave={() => { setPressed(false); sim.firing = false; }}
    >
      <div className="flex h-full w-full items-center justify-center">
        <div className="h-12 w-12 rounded-full bg-red-400/30" />
      </div>
    </button>
  );
}

// Dash button for mobile
function DashButton() {
  const [pressed, setPressed] = useState(false);

  return (
    <button
      className="pointer-events-auto absolute bottom-24 left-4 z-50 h-16 w-16 rounded-full bg-blue-500/80 shadow-[0_0_15px_rgba(61,232,255,0.6)] backdrop-blur-sm active:scale-95 active:bg-blue-400/90"
      onTouchStart={(e) => { e.preventDefault(); setPressed(true); sim.keys.add("shift"); }}
      onTouchEnd={(e) => { e.preventDefault(); setPressed(false); sim.keys.delete("shift"); }}
      onMouseDown={() => { setPressed(true); sim.keys.add("shift"); }}
      onMouseUp={() => { setPressed(false); sim.keys.delete("shift"); }}
      onMouseLeave={() => { setPressed(false); sim.keys.delete("shift"); }}
    >
      <div className="flex h-full w-full items-center justify-center font-mono text-xs font-bold text-white">
        DASH
      </div>
    </button>
  );
}

export function TouchControls() {
  const phase = useGame((s) => s.phase);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkMobile = () => {
      const mobile = "ontouchstart" in window || navigator.maxTouchPoints > 0;
      setIsMobile(mobile);
    };
    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  // Reset firing when leaving game
  useEffect(() => {
    if (phase !== "playing") {
      sim.firing = false;
      sim.keys.clear();
    }
  }, [phase]);

  if (!isMobile || phase === "menu" || phase === "gameover") {
    return null;
  }

  return (
    <>
      <VirtualJoystick
        onMove={(x, z) => {
          sim.keys.clear();
          if (z < -0.3) sim.keys.add("w");
          if (z > 0.3) sim.keys.add("s");
          if (x < -0.3) sim.keys.add("a");
          if (x > 0.3) sim.keys.add("d");
        }}
      />
      <FireButton />
      <DashButton />
      <TouchAim />

      {/* Instructions overlay */}
      <div className="pointer-events-none absolute bottom-36 left-4 z-50 text-[10px] text-white/40">
        <div className="mb-1">DRAG TO MOVE</div>
        <div>TAP TO FIRE</div>
      </div>
    </>
  );
}
"}

